const app = new Hono<{ Bindings: Bindings }>();

app.on(["GET", "POST"], "/api/auth/*", (c) => {
  const auth = createAuth(c.env, (promise) => c.executionCtx.waitUntil(promise));
  return auth.handler(c.req.raw);
});

const galleryCookieName = (code: string) => `memboux_gallery_${code.toLowerCase()}`;
const galleryAccessToken = (event: EventRow) => sha256(`gallery-access:${event.id}:${event.gallery_pin_hash}`);

async function adminSession(password: string) {
  return sha256(`memboux-admin-session:${password}`);
}

async function isAdmin(c: { env: Bindings; req: { header(name: string): string | undefined } }) {
  const password = c.env.ADMIN_PASSWORD;
  if (!password) return false;
  const cookie = c.req.header("Cookie") ?? "";
  const value = cookie.split(";").map((part) => part.trim()).find((part) => part.startsWith(`${ADMIN_COOKIE}=`))?.slice(ADMIN_COOKIE.length + 1);
  return Boolean(value && value === await adminSession(password));
}

function brandMark(href: string, compact = false, light = false) {
  const destination = /^\/(el|en)$/.test(href) ? `${href}/account` : href;
  return `<a href="${destination}" class="inline-flex items-center gap-3 ${light ? "text-white" : "text-[#594033]"}"><img src="/brand/memboux-icon.png" alt="" width="48" height="48" class="${compact ? "h-9 w-9" : "h-11 w-11"} object-contain ${light ? "brightness-0 invert" : ""}"><span class="leading-none"><strong class="block font-serif ${compact ? "text-xl" : "text-2xl"} tracking-wide">Memboux</strong><span class="mt-1 block text-[9px] font-semibold uppercase tracking-[.22em] opacity-75">Collecting Moments</span></span></a>`;
}

